-- W1.6 questions batch 256/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-5ff21eeb-moex-00132', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'essay', '甲受僱於乙公司當司機。某日甲外出送貨，見鄰居丙步行於大街，因此
主動向丙提出順路載送丙回家，丙欣然接受。途中，因甲超速駕駛發生
車禍，致丙受有重傷。丙請求甲、乙連帶賠償其損害。乙主張，甲分別
為乙的受僱人，同時因丙藉由甲之載送而擴充其活動範圍，因此甲同時
也是丙之使用人，則丙主張損害賠償時，亦有與有過失規定之適用，因
此應減輕乙的賠償金額或免除之。請分析當事人間之法律關係。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00133', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'essay', '甲將房屋出租給乙，租期 2年，租約中訂明「期滿不續租」。然甲因疫情
延宕返國，直至租期屆滿後 3 個月才回國，並傳 LINE 簡訊要求乙依租
賃原狀遷空交還。乙主張，甲於租期屆滿時不即表示反對乙繼續居住該
房屋，雙方的租賃契約已經變成不定期限租賃契約；且原租約屆滿後，
乙仍依原租約之約定於每月 5日給付租金於甲，甲亦予以受領該租金，
因此雙方租賃關係有效。試問，乙的主張是否有理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00134', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲借給乙一枝金筆，乙將該金筆賣給善意並無重大過失之丙，並現實交付之。下列敘述，何者正確？', '["甲得向乙主張因債務不履行之損害賠償", "甲得向乙主張所有物返還請求權", "甲得向丙主張所有物返還請求權", "甲得向丙主張不當得利返還請求權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00135', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '天上彩虹並非民法所稱之物，是因為下列何一理由？', '["因其為無體物", "因其非人類可支配", "因其存在於人體之外", "因其不具金錢價值"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00136', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲向乙購買A房地，為避免財產曝光，甲經友人丙之同意，由乙出賣人直接辦理A房地所有權移 轉登記於丙，但A房地交付於甲使用。甲又出資請丁裝潢A屋，並在A屋上加蓋B部分，再將 B部分出租於戊。嗣丙未經甲之同意，以A房地為標的物，就丙自己之債務為善意之債權人己設 定普通抵押權並完成登記。下列敘述，何者錯誤？', '["甲丙間之借名登記契約為無效", "甲丁間之承攬契約為有效", "甲戊間之租賃契約為有效", "丙己間之普通抵押權設定行為為有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00137', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列關於民法代理之敘述，何者錯誤？', '["甲雖無代理權，逕以乙之名義與丙訂立買賣契約，該買賣契約仍為有效", "乙委任甲代其出賣A車，甲以自己之名義出賣A車於丙，惟甲受丙之詐欺而訂立該買賣契約， 則甲得撤銷該契約", "甲之代理權授與行為與其基本法律關係原則上互相獨立", "甲之代理權授與行為之基礎內部法律關係無效，代理權授與行為原則上不受影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00138', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲乙訂有委任契約，並授權乙為甲購買A車，而乙以自己名義，向丙購買該車。下列敘述，何者 錯誤？', '["乙與丙之間成立買賣契約", "乙為間接代理", "乙既然受有代理權，則甲基於代理之效力，得請求丙交付A車", "甲與乙間之權利義務關係，依委任契約定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00139', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列關於同時履行抗辯權之敘述，何者錯誤？', '["行使同時履行抗辯權，只能暫時拒絕自己的給付，不能永久拒絕給付", "行使同時履行抗辯權，必須雙方當事人均無先為給付之義務", "他方當事人已為部分之給付時，皆不得行使同時履行抗辯權", "若他方已依債務本旨為給付，則不得拒絕自己之給付"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00140', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲將其對乙之新臺幣100萬元債權讓與丙。下列敘述，何者錯誤？', '["乙若有提供債權之擔保於甲，則該擔保隨同移轉於丙", "若甲未曾通知乙債權之讓與，則雖丙已向乙為債權讓與之通知，若乙仍向甲為給付，依民法規 定，即發生清償之效力", "甲有將證明債權之文件，交付丙之義務", "受讓人將讓與人所立之讓與字據提示於債務人者，與通知有同一之效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00141', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '「當事人之一方對他方負金錢或其他代替物之給付義務而約定以之作為消費借貸之標的」之契 約，關於該契約性質，下列敘述，何者錯誤？', '["成立消費借貸契約", "為不要式契約", "為物權契約", "為要因契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL)
